// Build-time loaders for the F2 dataset (generated by f2_predictions.export and
// the forward_eval / drift / promotion CLIs). Server components in a static
// export read these JSON files from disk at build time — no runtime fetches.

import { existsSync, readFileSync } from "node:fs";
import { join } from "node:path";

import type { CircuitGeometry, CircuitLibrary } from "@/types/circuit";
import type {
  CalibrationSummary,
  F2Data,
  ForwardEvalRound,
  ForwardEvalSeason,
  ModelHealth,
  ProbabilitiesRound,
  PromotionStatus,
  RoundDetail,
} from "@/types/f2";

const DATA_DIR = join(process.cwd(), "public", "data");

function readJson<T>(...segments: string[]): T | null {
  const path = join(DATA_DIR, ...segments);
  if (!existsSync(path)) return null;
  try {
    return JSON.parse(readFileSync(path, "utf-8")) as T;
  } catch {
    return null;
  }
}

function pad2(n: number): string {
  return String(n).padStart(2, "0");
}

let cache: F2Data | null = null;

export function getF2Data(): F2Data {
  if (cache) return cache;
  cache = readJson<F2Data>("f2.json");
  if (!cache) throw new Error("f2.json missing — run `python -m f2_predictions.export` first");
  return cache;
}

export function getRound(round: number): RoundDetail | null {
  return readJson<RoundDetail>("rounds", `round_${pad2(round)}.json`);
}

export function getProbabilities(round: number): ProbabilitiesRound | null {
  return readJson<ProbabilitiesRound>("probabilities", `round_${pad2(round)}.json`);
}

export function getCalibrationSummary(): CalibrationSummary | null {
  return readJson<CalibrationSummary>("calibration_summary.json");
}

export function getForwardEvalSeason(): ForwardEvalSeason | null {
  return readJson<ForwardEvalSeason>("forward_eval", "season.json");
}

export function getForwardEvalRounds(): ForwardEvalRound[] {
  const data = getF2Data();
  const rounds: ForwardEvalRound[] = [];
  for (let r = 1; r <= data.completedRounds; r++) {
    const rj = readJson<ForwardEvalRound>("forward_eval", `round_${pad2(r)}.json`);
    if (rj) rounds.push(rj);
  }
  return rounds;
}

export function getModelHealth(): ModelHealth | null {
  return readJson<ModelHealth>("model_health.json");
}

export function getPromotionStatus(): PromotionStatus | null {
  return readJson<PromotionStatus>("promotion_status.json");
}

// All calendar round numbers — for generateStaticParams on /race/[round].
export function allRoundNumbers(): number[] {
  return getF2Data().calendar.map((c) => c.round);
}

// Circuit outline geometry (F1 fastest-lap telemetry, shared circuits), keyed by
// venue key. Powers the SVG track map on the home + race pages, like the F1 site.
let circuitCache: CircuitLibrary | null = null;
export function getCircuits(): CircuitLibrary {
  if (!circuitCache) circuitCache = readJson<CircuitLibrary>("circuits.json") ?? {};
  return circuitCache;
}
export function getCircuit(venueKey: string | undefined | null): CircuitGeometry | null {
  if (!venueKey) return null;
  return getCircuits()[venueKey] ?? null;
}

const BASE_PATH = process.env.NEXT_PUBLIC_BASE_PATH || "";

// basePath-aware asset URL for static export (driver headshots, brand, …).
export function asset(path: string): string {
  return `${BASE_PATH}${path.startsWith("/") ? path : `/${path}`}`;
}

// `teamColor` now lives in the fs-free `./teams` module so client components can
// import it without pulling `node:fs` into the browser bundle. Re-exported here
// for server-side callers that already import it from this module.
export { teamColor } from "./teams";

// --------------------------------------------------------------------------- //
// Points-progression reconstruction (for the standings projection chart).
//
// The season JSON carries only end-of-season-to-date totals, not a per-round
// cumulative history. We rebuild cumulative points per driver/team from each
// completed round's sprint + feature finishing order using the F2 points table,
// then scale each entity's curve so its final value lands exactly on the known
// standings total (absorbing pole / fastest-lap bonus points we can't attribute
// per round). This keeps the chart's endpoint honest against the table.
// --------------------------------------------------------------------------- //
const F2_FEATURE_POINTS = [25, 18, 15, 12, 10, 8, 6, 4, 2, 1];
const F2_SPRINT_POINTS = [10, 8, 6, 5, 4, 3, 2, 1];

function pointsFor(position: number, table: number[]): number {
  return position >= 1 && position <= table.length ? table[position - 1] : 0;
}

export interface PointsProgression {
  /** Completed round numbers, e.g. [1,2,3,4,5,6,7]. */
  rounds: number[];
  /** Per-code cumulative points after each completed round. */
  byCode: Record<string, number[]>;
  /** Per-team cumulative points after each completed round. */
  byTeam: Record<string, number[]>;
}

export function getPointsProgression(): PointsProgression {
  const data = getF2Data();
  const completed = data.calendar.filter((c) => c.completed).map((c) => c.round);

  const codeTotals: Record<string, number[]> = {};
  const teamByCode: Record<string, string> = {};
  for (const d of data.driverStandings) {
    codeTotals[d.code] = [];
    teamByCode[d.code] = d.team;
  }

  let running: Record<string, number> = {};
  for (const code of Object.keys(codeTotals)) running[code] = 0;

  for (const round of completed) {
    const rd = getRound(round);
    if (rd) {
      for (const block of [rd.sprint, rd.feature] as const) {
        const table = block.raceType === "sprint" ? F2_SPRINT_POINTS : F2_FEATURE_POINTS;
        const results = block.actualResults ?? [];
        for (const res of results) {
          if (running[res.code] == null) running[res.code] = 0;
          running[res.code] += pointsFor(res.position, table);
        }
      }
    }
    for (const code of Object.keys(codeTotals)) {
      codeTotals[code].push(running[code] ?? 0);
    }
  }

  // Scale each driver's curve so the final value matches the known total.
  const byCode: Record<string, number[]> = {};
  for (const d of data.driverStandings) {
    const curve = codeTotals[d.code] ?? [];
    const last = curve[curve.length - 1] ?? 0;
    const scale = last > 0 ? d.points / last : 0;
    byCode[d.code] =
      last > 0 ? curve.map((v) => v * scale) : curve.map(() => 0);
    // Guarantee the endpoint is exactly the table value.
    if (byCode[d.code].length) byCode[d.code][byCode[d.code].length - 1] = d.points;
  }

  // Team curves = sum of their drivers' (scaled) curves, then snapped to total.
  const byTeam: Record<string, number[]> = {};
  for (const t of data.teamStandings) byTeam[t.team] = completed.map(() => 0);
  for (const d of data.driverStandings) {
    const team = teamByCode[d.code];
    const curve = byCode[d.code] ?? [];
    if (!byTeam[team]) byTeam[team] = completed.map(() => 0);
    for (let i = 0; i < curve.length; i++) byTeam[team][i] += curve[i] ?? 0;
  }
  for (const t of data.teamStandings) {
    const curve = byTeam[t.team] ?? [];
    if (curve.length) curve[curve.length - 1] = t.points;
  }

  return { rounds: completed, byCode, byTeam };
}
